* { box-sizing: border-box; }
body { margin: 0; background: #ffffff; color: #222; font-family: Arial, Helvetica, sans-serif; font-size: 15px; }
.receipt-page { width: 100%; max-width: 760px; margin: 0 auto; padding: 8px 0; }
.receipt-no { font-family: Georgia, serif; font-style: italic; font-size: 19px; margin-bottom: 12px; }
.receipt-no .line { display: inline-block; min-width: 120px; border-bottom: 1px dotted #333; text-align: center; font-size: 13px; font-weight: 700; font-style: normal; }
.amount-box { width: 198px; height: 40px; display: grid; grid-template-columns: 140px 58px; border: 1.5px solid #333; border-radius: 6px; overflow: hidden; background: #ffffff; }
.amount-box div { display: flex; align-items: center; justify-content: center; border-right: 1px solid #333; font-family: Georgia, serif; font-size: 16px; font-weight: 700; }
.amount-box div:last-child { border-right: 0; }
.receipt-title { text-align: center; line-height: 1.15; }
.receipt-title .arabic { font-size: 26px; font-weight: 700; }
.receipt-title .english { font-size: 22px; font-weight: 700; margin-top: 3px; }
.date-box { display: flex; justify-content: flex-end; align-items: center; gap: 7px; font-size: 16px; margin-bottom: 8px; }
.date-box .line { min-width: 118px; border-bottom: 1px dotted #333; text-align: center; font-family: Georgia, serif; font-weight: 700; padding-bottom: 2px; }
.arabic-text { direction: rtl; text-align: right; font-weight: 700; white-space: nowrap; }
.receipt-box { border: 1.7px solid #333; border-radius: 12px; padding: 17px 14px 20px; min-height: 335px; }
.receipt-row { display: flex; width: 100%; align-items: stretch; margin-bottom: 4px; }
.receipt-row .label { width: 28%; font-weight: bold; }
.receipt-row .value { width: 44%; min-height: 22px; border-bottom: 1px solid #000; padding: 2px 6px; line-height: 1.4; word-break: break-word; white-space: normal; }
.receipt-row .arabic-text { width: 28%; text-align: right; font-weight: bold; direction: rtl; }
.small-row { display: flex; width: 100%; align-items: center; margin-bottom: 4px; }
.small-row .label { width: 12%; font-size:12px; }
.small-row .small-line { width: 23%; min-height: 20px; border-bottom: 1px solid #000; padding: 2px 6px; }
.small-row .arabic-text { width: 12%; text-align: right; font-weight: bold; direction: rtl; }
.bank-label { width: 10%; font-weight: bold; padding-left: 8px; font-size:12px; }
.bank-line { width: 25%; min-height: 20px; border-bottom: 1px solid #000; padding: 2px 6px; }
.being-row { display: grid; grid-template-columns: 52px 1fr 80px; align-items: end; gap: 8px; margin-top: 8px; }
.being-row .value { min-height: 48px; padding: 2px 10px; }
.blank-line { border-bottom: 1px dotted #444; height: 30px; margin: 0 0 28px; }
.signatures { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 44px; padding: 0 12px; margin-top: 14px; }
.signature { border-top: 1px dotted #444; padding-top: 6px; display: flex; justify-content: space-between; align-items: baseline; font-weight: 700; }
.signature .en { font-size: 13px; }
.signature .ar { direction: rtl; font-size: 15px; }
.footer-contact-box { width: 100%; border: 1px solid #222; border-radius: 8px; padding: 10px 14px; font-size: 13px; line-height: 1.6; box-sizing: border-box; margin-top: 10px; }
.footer-contact-line { display: flex; align-items: center; justify-content: center; gap: 8px; white-space: nowrap; flex-wrap: wrap; }
.footer-ar { direction: rtl; unicode-bidi: isolate; font-weight: bold; }
</style>

{%- set amount_value = doc.received_amount if doc.payment_type == "Receive" else doc.paid_amount -%}
{%- set amount_text = "%.2f"|format(amount_value or 0) -%}
{%- set amount_parts = amount_text.split('.') -%}
{%- set currency = doc.paid_to_account_currency if doc.payment_type == "Receive" else doc.paid_from_account_currency -%}
{%- set main_account = doc.paid_to if doc.payment_type == "Receive" else doc.paid_from -%}

<div class="receipt-page">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;">
    <div>
      <div class="receipt-no">No. <span class="line">{{ doc.name }}</span></div>
      <div style="font-size:13px;display:flex;gap:6px;margin-bottom:2px;"><span>{{ currency or "Amount" }}</span><span>Fils</span></div>
      <div class="amount-box">
        <div>{{ frappe.utils.fmt_money(amount_value or 0, currency=currency) }}</div>
        <div>{{ amount_parts[1] }}</div>
      </div>
    </div>
    <div class="receipt-title">
      <div class="arabic">سند قبض</div>
      <div class="english">Receipt Voucher</div>
    </div>
    <div class="date-box">
      <span>Date:</span>
      <span class="line">{{ frappe.utils.formatdate(doc.posting_date, "dd/MM/yy") }}</span>
      <span class="arabic-text">: التاريخ</span>
    </div>
  </div>

  <div class="receipt-box">
    <div class="receipt-row">
      <div class="label">Received from Mr./M/s.</div>
      <div class="value">{{ doc.party_name or doc.party or "" }}</div>
      <div class="arabic-text">استلمنا من السيد / السادة</div>
    </div>
    <div class="receipt-row">
      <div class="label">The sum of</div>
      <div class="value">{{ doc.in_words or doc.base_in_words or "" }}</div>
      <div class="arabic-text">مبلغ وقدره</div>
    </div>
    <div class="receipt-row">
      <div class="label">By Cash / Cheque No.</div>
      <div class="value payment-detail">
        {{ doc.mode_of_payment or "" }}
        {%- if doc.reference_no -%}<br>Ref No: {{ doc.reference_no }}{%- endif -%}
        {%- if doc.reference_date -%}<br>Ref Date: {{ frappe.utils.formatdate(doc.reference_date, "dd/MM/yy") }}{%- endif -%}
        {%- if doc.bank -%}<br>Bank: {{ doc.bank }}{%- endif -%}
      </div>
      <div class="arabic-text">نقداً / شيك رقم</div>
    </div>
    <div class="small-row">
      <div class="label">Dated</div>
      <div class="small-line">{{ frappe.utils.formatdate(doc.reference_date, "dd/MM/yy") if doc.reference_date else "" }}</div>
      <div class="arabic-text">بتاريخ</div>
      <div class="bank-label">Bank</div>
      <div class="bank-line">{{ doc.bank or doc.bank_account or main_account or "" }}</div>
      <div class="arabic-text">البنك</div>
    </div>
    <div class="being-row">
      <div class="label" style="font-size:12px;">Being</div>
      <div class="value">{{ doc.remarks or "" }}</div>
      <div class="arabic-text">وذلك عن</div>
    </div>
    <div class="blank-line"></div>
    <div class="signatures">
      <div class="signature"><span class="en">Received by</span><span class="ar">المستلم</span></div>
      <div class="signature"><span class="en">Manager's Sign.</span><span class="ar">توقيع المدير</span></div>
      <div class="signature"><span class="en">Accountant</span><span class="ar">المحاسب</span></div>
    </div>
  </div>

  <div class="footer-contact-box">
    <div class="footer-contact-line">
      <span>Tel.: +971 2 262 5959</span>
      <span>- Fax: +971 2 626 5991</span>
      <span>- P.O.Box: 4358, Abu Dhabi, U.A.E.</span>
    </div>
    <div class="footer-contact-line">
      <span class="footer-ar">ص.ب: ٤٣٥٨، أبوظبي، ا.ع.م</span>
      <span class="footer-ar">- فاكس: +٩٧١ ٢ ٦٢٦ ٥٩٩١</span>
      <span class="footer-ar">- هاتف: +٩٧١ ٢ ٢٦٢ ٥٩٥٩</span>
    </div>
    <div class="footer-contact-line">
      <span>website: www.alkhajaholding.com</span>
      <span class="footer-ar">الموقع الإلكتروني</span>
      <span>E-mail: realestate@alkhajaholding.com</span>
      <span class="footer-ar">البريد الإلكتروني</span>
    </div>
  </div>
</div>"}]
